spring.application.name=placement-portal

# Render and other hosts often set PORT; local default 5001
server.port=${PORT:5001}
server.servlet.context-path=/

# MongoDB
spring.data.mongodb.uri=${MONGO_URI}
spring.data.mongodb.database=${MONGO_DATABASE:placement-portal}
spring.data.mongodb.auto-index-creation=true

# JWT
jwt.secret=${JWT_SECRET}
jwt.expiration=${JWT_EXPIRATION:2592000000}

# Email
spring.mail.host=${EMAIL_HOST:smtp.gmail.com}
spring.mail.port=${EMAIL_PORT:587}
spring.mail.username=${EMAIL_USER}
spring.mail.password=${EMAIL_PASS}
spring.mail.properties.mail.smtp.auth=true
spring.mail.properties.mail.smtp.starttls.enable=true
spring.mail.properties.mail.smtp.starttls.required=true
spring.mail.default-encoding=UTF-8

# Logging
logging.level.root=INFO
logging.level.com.placementportal=${LOGGING_LEVEL_COM_PLACEMENTPORTAL:INFO}

# Admin configuration
app.admin-emails=${ADMIN_EMAILS:}

# Demo data seeding
app.seed-demo-data=${SEED_DATA:false}

# AI/Groq configuration
app.ai.api-key=${AI_API_KEY:}
app.ai.base-url=${AI_BASE_URL:https://api.groq.com/openai/v1}
app.ai.model=${AI_MODEL:llama-3.3-70b-versatile}

# CORS configuration
app.cors.allowed-origin-patterns=${CORS_ALLOWED_ORIGINS:}

